<template lang='pug'>
.wrapper()
  .stage0(v-if='STAGE(roomId)==0')
    card(
      v-for='c in CARDS'
      :class="{chosen: c.id==SECRET(roomId)}"
      :c='c'
      :key='c.id'
      @choose='choose'
    )
    button.start(
      @click='startGame'
      :disabled='SECRET(roomId)==null'
    ) START
  .stage1(v-if='STAGE(roomId)==1')
    p PAPAPP
    button.start(
      @click='reset()'
    ) RESET

</template>

<script>
import {mapGetters, mapActions, mapMutations} from 'vuex'
import card from '../views/card.vue'
export default {
  data:()=>({
    roomId:0
  }),
  components:{card},
  computed:{
    ...mapGetters(['CARDS','STAGE','SECRET'])
  },
  methods:{
    ...mapActions,
    ...mapMutations,
    choose(id){
      this.$store.commit('CHOOSE_SECRET',[this.roomId,id])
    },
    async reset(){
      await this.$store.commit('RESET',[this.roomId])
    },
    async startGame(){
      await this.$store.dispatch('START_GAME',[this.roomId,this.secretCard])
      await this.$store.commit('NEXT_STAGE',[this.roomId])
    }
  },
  mounted() {
    this.roomId = this.$route.params.roomId
  }
}
</script>

<style lang='stylus'>
.stage0
  display flex
  .chosen
    box-shadow 10px 5px 5px blue
  .card
    height 90px
    background-size cover
    background-repeat no-repeat
    background-position center center
    margin 10px 10px
    border 4px solid
    border-radius 5px
    :hover
      box-shadow 10px 5px 5px green
      transform translate(6px,7px)
      transition .2s
</style>