<template lang='pug'>
img.card(
  :src="require(`../assets/cards/`+c.pic)"
  @click='choose(c.id)'
  )
</template>

<script>
export default {
  data:()=>({
  
  }),
  props:{
    c:Object
  },
  methods:{
    choose(id){
      this.$emit('choose', id)
    }
  }
}
</script>

<style lang='stylus'>
.card
  height 90px
  background-size cover
  background-repeat no-repeat
  background-position center center
  margin 10px 10px
  border 4px solid
  border-radius 5px
.card:hover
  box-shadow 10px 5px 5px green
  transform translate(6px,7px)
  transition .2s
</style>